// ============================================================================
// PROGRESS BAR COMPONENT
// ============================================================================

function ProgressBar({ steps, currentStepIndex }: { steps: Step[]; currentStepIndex: number }) {
  return (
    <div className="w-full px-4 py-4">
      {/* Mobile: Simple progress */}
      <div className="md:hidden">
        <div className="flex items-center justify-between mb-2">
          <span className="text-sm text-white/60">Step {currentStepIndex + 1} of {steps.length}</span>
          <span className="text-sm text-cyan-400 font-medium">{steps[currentStepIndex].name}</span>
        </div>
        <div className="h-2 bg-slate-700 rounded-full overflow-hidden">
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${((currentStepIndex + 1) / steps.length) * 100}%` }}
            transition={{ duration: 0.5, ease: 'easeOut' }}
            className="h-full bg-gradient-to-r from-cyan-500 to-blue-500"
          />
        </div>
      </div>

      {/* Desktop: Full step indicators */}
      <div className="hidden md:flex items-center justify-center gap-2">
        {steps.map((step, index) => {
          const isActive = index === currentStepIndex;
          const isCompleted = index < currentStepIndex;
          
          return (
            <React.Fragment key={step.id}>
              <motion.div
                initial={{ scale: 0.8, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ delay: index * 0.1 }}
                className="flex items-center gap-2"
              >
                <div
                  className={cn(
                    'w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300',
                    isCompleted && 'bg-gradient-to-r from-cyan-500 to-blue-500 text-white',
                    isActive && 'bg-cyan-500/20 border-2 border-cyan-400 text-cyan-400',
                    !isActive && !isCompleted && 'bg-slate-800 border border-slate-600 text-slate-500'
                  )}
                >
                  {isCompleted ? (
                    <Check className="w-5 h-5" />
                  ) : (
                    step.icon
                  )}
                </div>
                <div className="hidden lg:block">
                  <p className={cn(
                    'text-sm font-medium transition-colors',
                    isActive ? 'text-white' : 'text-slate-400'
                  )}>
                    {step.name}
                  </p>
                </div>
              </motion.div>
              
              {index < steps.length - 1 && (
                <div className={cn(
                  'w-8 lg:w-12 h-0.5 transition-colors',
                  index < currentStepIndex ? 'bg-cyan-500' : 'bg-slate-700'
                )} />
              )}
            </React.Fragment>
          );
        })}
      </div>
    </div>
  );
}

