// ============================================================================
// STEP 2: CONNECT TOOLS
// ============================================================================

function ConnectToolsStep({
  connectedTools,
  onConnect,
  onNext,
  onBack,
}: {
  connectedTools: string[];
  onConnect: (toolId: string) => void;
  onNext: () => void;
  onBack: () => void;
}) {
  const [connecting, setConnecting] = useState<string | null>(null);

  const handleConnect = async (toolId: string) => {
    if (connectedTools.includes(toolId)) return;
    
    setConnecting(toolId);
    // Simulate connection delay
    await new Promise(resolve => setTimeout(resolve, 1500));
    onConnect(toolId);
    setConnecting(null);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      className="px-4 max-w-4xl mx-auto w-full"
    >
      <div className="text-center mb-8">
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          className="w-16 h-16 rounded-full bg-gradient-to-r from-cyan-500 to-blue-500 flex items-center justify-center mx-auto mb-4"
        >
          <Link2 className="w-8 h-8 text-white" />
        </motion.div>
        <h2 className="text-2xl md:text-3xl font-bold text-white mb-2">Connect Your Tools</h2>
        <p className="text-white/60">Give your AI specialists access to your business tools</p>
      </div>

      {/* Connected count */}
      {connectedTools.length > 0 && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          className="bg-cyan-500/10 border border-cyan-500/30 rounded-xl p-4 mb-6 text-center"
        >
          <p className="text-cyan-300">
            <CheckCircle className="w-5 h-5 inline mr-2" />
            {connectedTools.length} tool{connectedTools.length > 1 ? 's' : ''} connected! Your specialists can now access{' '}
            {connectedTools.map(id => CONNECTORS.find(c => c.id === id)?.name).filter(Boolean).join(', ')}.
          </p>
        </motion.div>
      )}

      {/* Tools grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 mb-8">
        {CONNECTORS.map((connector, index) => {
          const isConnected = connectedTools.includes(connector.id);
          const isConnecting = connecting === connector.id;
          
          return (
            <motion.div
              key={connector.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: index * 0.05 }}
              className={cn(
                'relative bg-slate-900/60 backdrop-blur-xl rounded-xl border p-4 transition-all',
                isConnected 
                  ? 'border-cyan-500/50 bg-cyan-500/10' 
                  : 'border-slate-700 hover:border-cyan-500/30'
              )}
            >
              <div className="flex items-start gap-4">
                <div className={cn(
                  'w-14 h-14 rounded-xl bg-gradient-to-r flex items-center justify-center text-white',
                  connector.color
                )}>
                  {connector.icon}
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="font-semibold text-white">{connector.name}</h3>
                  <p className="text-sm text-white/50 truncate">{connector.description}</p>
                </div>
              </div>
              
              <button
                onClick={() => handleConnect(connector.id)}
                disabled={isConnected || isConnecting}
                className={cn(
                  'mt-4 w-full py-2 rounded-lg font-medium text-sm transition-all flex items-center justify-center gap-2',
                  isConnected
                    ? 'bg-cyan-500/20 text-cyan-400 cursor-default'
                    : isConnecting
                    ? 'bg-slate-700 text-white/50 cursor-wait'
                    : 'bg-slate-700 hover:bg-cyan-500/20 text-white hover:text-cyan-400 cursor-pointer'
                )}
              >
                {isConnected ? (
                  <>
                    <Check className="w-4 h-4" />
                    Connected
                  </>
                ) : isConnecting ? (
                  <>
                    <motion.div
                      animate={{ rotate: 360 }}
                      transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
                    >
                      <Settings className="w-4 h-4" />
                    </motion.div>
                    Connecting...
                  </>
                ) : (
                  <>
                    <Zap className="w-4 h-4" />
                    Connect
                  </>
                )}
              </button>
            </motion.div>
          );
        })}
      </div>

      {/* Navigation */}
      <div className="flex flex-col sm:flex-row gap-3 justify-between">
        <button
          onClick={onBack}
          className="px-6 py-3 text-white/60 hover:text-white transition-colors flex items-center justify-center gap-2"
        >
          <ArrowLeft className="w-5 h-5" />
          Back
        </button>
        <button
          onClick={onNext}
          className="bg-gradient-to-r from-cyan-500 to-blue-500 text-white font-semibold px-8 py-3 rounded-xl shadow-lg shadow-cyan-500/30 hover:shadow-cyan-500/50 transition-all flex items-center justify-center gap-2"
        >
          {connectedTools.length > 0 ? 'Continue' : 'Skip for now'}
          <ArrowRight className="w-5 h-5" />
        </button>
      </div>
    </motion.div>
  );
}

// ============================================================================
// STEP 3: MEET YOUR SPECIALISTS
// ============================================================================

function MeetSpecialistsStep({
  specialists,
  onNext,
  onBack,
}: {
  specialists: Specialist[];
  onNext: () => void;
  onBack: () => void;
}) {
  const [selectedSpecialist, setSelectedSpecialist] = useState<Specialist | null>(null);
  const [chatMessages, setChatMessages] = useState<Array<{ role: 'user' | 'assistant'; content: string }>>([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const handleSelectSpecialist = (specialist: Specialist) => {
    setSelectedSpecialist(specialist);
    setChatMessages([{ role: 'assistant', content: specialist.greeting }]);
  };

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedSpecialist) return;
    
    const userMessage = inputValue.trim();
    setInputValue('');
    setChatMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    
    // Simulate AI response
    setIsTyping(true);
    await new Promise(resolve => setTimeout(resolve, 1000 + Math.random() * 1000));
    
    const responses = [
      `That's a great question! As your ${selectedSpecialist.role}, I can help with that using ${selectedSpecialist.capabilities[0].toLowerCase()}.`,
      `I'd love to help with that! One of my specialties is ${selectedSpecialist.capabilities[1].toLowerCase()}.`,
      `Absolutely! I'm here to make your work easier. Let me show you what I can do with ${selectedSpecialist.capabilities[2].toLowerCase()}.`,
    ];
    
    setChatMessages(prev => [...prev, { 
      role: 'assistant', 
      content: responses[Math.floor(Math.random() * responses.length)] 
    }]);
    setIsTyping(false);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -20 }}
      className="px-4 max-w-5xl mx-auto w-full"
    >
      <div className="text-center mb-8">
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          className="w-16 h-16 rounded-full bg-gradient-to-r from-cyan-500 to-blue-500 flex items-center justify-center mx-auto mb-4"
        >
          <Users className="w-8 h-8 text-white" />
        </motion.div>
        <h2 className="text-2xl md:text-3xl font-bold text-white mb-2">Meet Your AI Specialists</h2>
        <p className="text-white/60">Get to know your team and their capabilities</p>
      </div>

      <div className="grid lg:grid-cols-2 gap-6">
        {/* Specialists list */}
        <div className="space-y-4">
          {specialists.map((specialist, index) => (
            <motion.div
              key={specialist.id}
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: index * 0.1 }}
              onClick={() => handleSelectSpecialist(specialist)}
              className={cn(
                'bg-slate-900/60 backdrop-blur-xl rounded-xl border p-4 cursor-pointer transition-all',
                selectedSpecialist?.id === specialist.id
                  ? 'border-cyan-500/50 bg-cyan-500/10'
                  : 'border-slate-700 hover:border-cyan-500/30'
              )}
            >
              <div className="flex items-start gap-4">
                <div className="w-14 h-14 rounded-full bg-gradient-to-r from-cyan-500/20 to-blue-500/20 flex items-center justify-center text-3xl">
                  {specialist.avatar}
                </div>
                <div className="flex-1">
                  <h3 className="font-semibold text-white">{specialist.name}</h3>
                  <p className="text-sm text-cyan-400">{specialist.role}</p>
                  <div className="flex flex-wrap gap-2 mt-2">
                    {specialist.capabilities.slice(0, 2).map((cap, i) => (
                      <span key={i} className="text-xs bg-slate-700/50 text-white/60 px-2 py-1 rounded">
                        {cap}
                      </span>
                    ))}
                  </div>
                </div>
                <ChevronRight className={cn(
                  'w-5 h-5 transition-colors',
                  selectedSpecialist?.id === specialist.id ? 'text-cyan-400' : 'text-slate-500'
                )} />
              </div>
            </motion.div>
          ))}
        </div>

        {/* Chat preview */}
        <div className="bg-slate-900/60 backdrop-blur-xl rounded-xl border border-slate-700 overflow-hidden flex flex-col min-h-[400px]">
          {selectedSpecialist ? (
            <>
              {/* Chat header */}
              <div className="bg-slate-800/80 px-4 py-3 border-b border-slate-700 flex items-center gap-3">
                <div className="w-10 h-10 rounded-full bg-gradient-to-r from-cyan-500/20 to-blue-500/20 flex items-center justify-center text-xl">
                  {selectedSpecialist.avatar}
                </div>
                <div>
                  <h4 className="font-medium text-white">{selectedSpecialist.name}</h4>
                  <p className="text-xs text-green-400">Online</p>
                </div>
              </div>
              
              {/* Chat messages */}
              <div className="flex-1 p-4 space-y-4 overflow-y-auto">
                {chatMessages.map((msg, index) => (
                  <motion.div
                    key={index}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className={cn(
                      'max-w-[80%] p-3 rounded-2xl',
                      msg.role === 'user'
                        ? 'ml-auto bg-cyan-500 text-white rounded-br-sm'
                        : 'bg-slate-700 text-white/90 rounded-bl-sm'
                    )}
                  >
                    {msg.content}
                  </motion.div>
                ))}
                {isTyping && (
                  <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="bg-slate-700 text-white/60 p-3 rounded-2xl rounded-bl-sm max-w-[80%]"
                  >
                    <motion.span
                      animate={{ opacity: [0.5, 1, 0.5] }}
                      transition={{ duration: 1.5, repeat: Infinity }}
                    >
                      {selectedSpecialist.name} is typing...
                    </motion.span>
                  </motion.div>
                )}
              </div>
              
              {/* Chat input */}
              <div className="p-4 border-t border-slate-700">
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                    placeholder={`Ask ${selectedSpecialist.name} something...`}
                    className="flex-1 bg-slate-800 border border-slate-600 rounded-xl px-4 py-2 text-white placeholder:text-slate-500 focus:outline-none focus:border-cyan-500"
                  />
                  <button
                    onClick={handleSendMessage}
                    disabled={!inputValue.trim()}
                    className="w-10 h-10 bg-cyan-500 hover:bg-cyan-400 disabled:bg-slate-700 disabled:text-slate-500 text-white rounded-xl flex items-center justify-center transition-colors"
                  >
                    <Send className="w-5 h-5" />
                  </button>
                </div>
              </div>
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center text-slate-500">
              <div className="text-center">
                <MessageCircle className="w-12 h-12 mx-auto mb-3 opacity-50" />
                <p>Select a specialist to chat</p>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Navigation */}
      <div className="flex flex-col sm:flex-row gap-3 justify-between mt-8">
        <button
          onClick={onBack}
          className="px-6 py-3 text-white/60 hover:text-white transition-colors flex items-center justify-center gap-2"
        >
          <ArrowLeft className="w-5 h-5" />
          Back
        </button>
        <button
          onClick={onNext}
          className="bg-gradient-to-r from-cyan-500 to-blue-500 text-white font-semibold px-8 py-3 rounded-xl shadow-lg shadow-cyan-500/30 hover:shadow-cyan-500/50 transition-all flex items-center justify-center gap-2"
        >
          Continue
          <ArrowRight className="w-5 h-5" />
        </button>
      </div>
    </motion.div>
  );
}

