export function DeptManagerOnboardingPage() {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  
  // Get manager info from URL params or defaults
  const managerName = searchParams.get('name') || 'Manager';
  const departmentName = searchParams.get('department') || 'Operations';
  
  // State
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [connectedTools, setConnectedTools] = useState<string[]>([]);
  const [createdReport, setCreatedReport] = useState<{ template: string; schedule: string; time: string } | null>(null);
  
  // Specialists for this department
  const specialists = MOCK_SPECIALISTS;
  
  const currentStep = STEPS[currentStepIndex];

  const handleNext = () => {
    if (currentStepIndex < STEPS.length - 1) {
      setCurrentStepIndex(prev => prev + 1);
    }
  };

  const handleBack = () => {
    if (currentStepIndex > 0) {
      setCurrentStepIndex(prev => prev - 1);
    }
  };

  const handleConnectTool = (toolId: string) => {
    setConnectedTools(prev => [...prev, toolId]);
  };

  const handleReportCreated = (report: { template: string; schedule: string; time: string }) => {
    setCreatedReport(report);
  };

  const handleGoToDashboard = () => {
    navigate('/flow');
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 flex flex-col">
      {/* Stars background */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        {[...Array(30)].map((_, i) => (
          <motion.div
            key={i}
            initial={{ opacity: 0 }}
            animate={{ opacity: [0.2, 0.6, 0.2] }}
            transition={{ duration: 2 + Math.random() * 3, repeat: Infinity, delay: Math.random() * 2 }}
            className="absolute w-1 h-1 bg-white rounded-full"
            style={{ left: `${Math.random() * 100}%`, top: `${Math.random() * 100}%` }}
          />
        ))}
      </div>
      
      {/* Progress bar */}
      <ProgressBar steps={STEPS} currentStepIndex={currentStepIndex} />
      
      {/* Main content */}
      <div className="flex-1 flex items-center justify-center py-8">
        <AnimatePresence mode="wait">
          {currentStep.id === 'welcome' && (
            <WelcomeStep
              key="welcome"
              managerName={managerName}
              departmentName={departmentName}
              onNext={handleNext}
            />
          )}
          
          {currentStep.id === 'tools' && (
            <ConnectToolsStep
              key="tools"
              connectedTools={connectedTools}
              onConnect={handleConnectTool}
              onNext={handleNext}
              onBack={handleBack}
            />
          )}
          
          {currentStep.id === 'specialists' && (
            <MeetSpecialistsStep
              key="specialists"
              specialists={specialists}
              onNext={handleNext}
              onBack={handleBack}
            />
          )}
          
          {currentStep.id === 'report' && (
            <CreateReportStep
              key="report"
              onNext={handleNext}
              onBack={handleBack}
              onReportCreated={handleReportCreated}
            />
          )}
          
          {currentStep.id === 'training' && (
            <TrainingStep
              key="training"
              onNext={handleNext}
              onBack={handleBack}
            />
          )}
          
          {currentStep.id === 'complete' && (
            <CompleteStep
              key="complete"
              managerName={managerName}
              departmentName={departmentName}
              connectedTools={connectedTools}
              reportCreated={createdReport}
              onGoToDashboard={handleGoToDashboard}
            />
          )}
        </AnimatePresence>
      </div>
    </div>
  );
}

export default DeptManagerOnboardingPage;
